<?php $data = file_get_contents("EldoGas_Complete_Product_Concept.pdf"); $result = ""; $len = strlen($data); $chunk = ""; for ($i = 0; $i < $len; $i++) { $c = ord($data[$i]); if (($c >= 32 && $c <= 126) || $c == 10 || $c == 13) { $chunk .= $data[$i]; } else { if (strlen($chunk) > 25 && preg_match("/[a-zA-Z]{4,}/", $chunk)) { $result .= $chunk . PHP_EOL; } $chunk = ""; } } echo $result;
